// ============================================================
//  NAVIGATION
// ============================================================

function showStep(step) {
    document.querySelectorAll('.step-section').forEach(s => s.classList.remove('active'));
    document.getElementById(`step-${step}`).classList.add('active');
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

function goBack() {
    showStep(1);
    currentLetter = null;
}

function resetApp() {
    showStep(1);
    currentLetter = null;
    document.getElementById('letter-form').reset();
}

// ============================================================
//  HELPERS
// ============================================================

function getFieldValue(id) {
    const el = document.getElementById(`field-${id}`);
    if (!el) return '';
    
    // Feature: Handle "OTRA" for selects
    if (el.tagName === 'SELECT' && el.value === 'OTRA') {
        const manualEl = document.getElementById(`field-${id}-manual`);
        return manualEl ? manualEl.value.trim() : 'Otra';
    }
    
    return el.value.trim();
}

function handleSelectChange(selectEl, fieldId) {
    const manualContainer = document.getElementById(`manual-container-${fieldId}`);
    if (manualContainer) {
        if (selectEl.value === 'OTRA') {
            manualContainer.style.display = 'block';
            const manualInput = document.getElementById(`field-${fieldId}-manual`);
            if (manualInput) manualInput.focus();
        } else {
            manualContainer.style.display = 'none';
        }
    }
}

function formatDate(dateStr) {
    if (!dateStr) return '';
    const d = new Date(dateStr + 'T12:00:00');
    const months = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio',
        'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
    return `${d.getDate()} de ${months[d.getMonth()]} de ${d.getFullYear()}`;
}

function getBeneficiaries() {
    const rows = document.querySelectorAll('#beneficiary-rows .beneficiary-row');
    const data = [];
    rows.forEach((row, i) => {
        const nombre = row.querySelector(`input[name="ben_nombre_${row.dataset.row}"]`)?.value?.trim() || '';
        const parentesco = row.querySelector(`input[name="ben_parentesco_${row.dataset.row}"]`)?.value?.trim() || '';
        const doc = row.querySelector(`input[name="ben_doc_${row.dataset.row}"]`)?.value?.trim() || '';
        const pct = row.querySelector(`input[name="ben_pct_${row.dataset.row}"]`)?.value?.trim() || '';
        if (nombre) data.push({ nombre, parentesco, doc, pct });
    });
    return data;
}

function getTrasladarList() {
    const rows = document.querySelectorAll('#trasladar-rows .trasladar-row');
    const data = [];
    rows.forEach(row => {
        const nombre = row.querySelector(`input[name="tras_nombre_${row.dataset.row}"]`)?.value?.trim() || '';
        const id = row.querySelector(`input[name="tras_id_${row.dataset.row}"]`)?.value?.trim() || '';
        if (nombre) data.push({ nombre, id });
    });
    return data;
}

// ============================================================
//  PDF GENERATION
// ============================================================

function generatePDF(e) {
    e.preventDefault();
    console.log("Starting PDF generation...");

    try {
        // Safe access to jsPDF
        const jsPDFLib = window.jspdf ? window.jspdf.jsPDF : (window.jsPDF ? window.jsPDF : null);
        
        if (!jsPDFLib) {
            alert("Error: La librería de PDF no ha cargado correctamente. Por favor, revisa tu conexión a internet.");
            return;
        }

        const doc = new jsPDFLib('p', 'mm', 'letter');

        const pageWidth = doc.internal.pageSize.getWidth();
        const pageHeight = doc.internal.pageSize.getHeight();
        const marginLeft = 25;
        const marginRight = 25;
        const contentWidth = pageWidth - marginLeft - marginRight;
        let y = 20;

        // ---- Logo (Using embedded Base64 for maximum reliability) ----
        if (typeof LOGO_BASE64 !== 'undefined' && LOGO_BASE64) {
            const logoW = 45;
            // Standard aspect ratio for GuíaBien logo is approx 1.2 : 1 (W:H)
            const logoH = logoW * (1 / 1.2); 
            try {
                doc.addImage(LOGO_BASE64, 'PNG', marginLeft, y, logoW, logoH);
                y += logoH + 12;
            } catch (imgErr) {
                console.warn("Could not add embedded logo to PDF:", imgErr);
                y += 15;
            }
        } else {
            // Fallback: Check if logo exists in DOM
            const logoImg = document.getElementById('logo-img');
            if (logoImg && logoImg.complete && logoImg.naturalWidth !== 0) {
                const logoW = 45;
                const aspectRatio = logoImg.naturalHeight / logoImg.naturalWidth;
                const logoH = logoW * aspectRatio;
                try {
                    doc.addImage(logoImg, 'PNG', marginLeft, y, logoW, logoH);
                    y += logoH + 12;
                } catch (imgErr) {
                    y += 15;
                }
            } else {
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(18);
                doc.setTextColor(26, 35, 126);
                doc.text('GuíaBien Asesores en Seguros', marginLeft, y + 10);
                y += 25;
            }
        }

        // ---- Thin orange line ----
        doc.setDrawColor(245, 166, 35);
        doc.setLineWidth(0.8);
        doc.line(marginLeft, y, pageWidth - marginRight, y);
        y += 10;

        // ---- Routing to letter-specific generator ----
        switch (currentLetter.id) {
            case 'cambio_intermediario': generateCambioIntermediario(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'actualizacion_beneficiarios': generateActualizacionBeneficiarios(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'cambio_periodicidad': generateCambioPeriodicidad(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'cancelacion_poliza': generateCancelacionPoliza(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'apertura_colectiva': generateAperturaColectiva(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;

            case 'cambio_tomador': generateCambioTomador(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'devolucion_saldo': generateDevolucionSaldo(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'presentacion_condiciones': generatePresentacionCondiciones(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
            case 'rehabilitacion': generateRehabilitacion(doc, y, marginLeft, contentWidth, pageWidth, marginRight); break;
        }

        // ---- Save ----
        // Try to find the client's name from form fields
        let clientName = '';
        const nameFields = ['nombre_tomador', 'nombre_empresa', 'nombre_firmante', 'nombre_tomador_actual', 'nombre_representante'];
        
        for (const fieldId of nameFields) {
            const input = document.querySelector(`[name="${fieldId}"]`);
            if (input && input.value.trim()) {
                clientName = input.value.trim();
                break;
            }
        }

        const baseTitle = currentLetter.title.normalize("NFD").replace(/[\u0300-\u036f]/g, ""); // remove accents
        let cleanClientName = clientName.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        cleanClientName = cleanClientName.replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '_');
        
        if (cleanClientName) cleanClientName = "_" + cleanClientName;

        const fileName = `${baseTitle.replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '_')}${cleanClientName}.pdf`;
        
        doc.save(fileName);
        console.log("PDF generated successfully:", fileName);
        showStep(3);

    } catch (err) {
        console.error("Critical error in PDF generation:", err);
        alert("Ocurrió un error al generar el PDF. Por favor abre la consola del navegador (F12) para ver los detalles.");
    }
}

// ============================================================
//  PDF HELPER FUNCTIONS
// ============================================================

function pdfSetNormal(doc) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(11);
    doc.setTextColor(30, 30, 30);
}

function pdfSetBold(doc) {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.setTextColor(30, 30, 30);
}

function pdfSetSmall(doc) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.setTextColor(80, 80, 80);
}

function pdfSetSubject(doc) {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.setTextColor(26, 35, 126);
}

function pdfWriteText(doc, text, x, y, maxWidth) {
    const lines = doc.splitTextToSize(text, maxWidth);
    doc.text(lines, x, y);
    return y + (lines.length * 5.5);
}

function pdfDrawSignatureLine(doc, y, marginLeft, contentWidth) {
    y += 8;
    doc.setDrawColor(30, 30, 30);
    doc.setLineWidth(0.3);
    doc.line(marginLeft, y, marginLeft + 65, y);
    y += 5;
    return y;
}

function pdfFooter(doc, pageWidth, pageHeight) {
    doc.setDrawColor(245, 166, 35);
    doc.setLineWidth(0.5);
    doc.line(25, pageHeight - 18, pageWidth - 25, pageHeight - 18);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(120, 120, 120);
    doc.text('GuíaBien Asesores en Seguros · Código 3052 · www.guiabien.com', pageWidth / 2, pageHeight - 12, { align: 'center' });
}

function pdfDrawTable(doc, headers, rows, x, y, colWidths) {
    const cellHeight = 7;
    const padding = 3;

    // Header
    doc.setFillColor(26, 35, 126);
    let totalW = colWidths.reduce((a, b) => a + b, 0);
    doc.rect(x, y, totalW, cellHeight, 'F');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(255, 255, 255);
    let cx = x;
    headers.forEach((h, i) => {
        doc.text(h, cx + padding, y + 5);
        cx += colWidths[i];
    });
    y += cellHeight;

    // Rows
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.setTextColor(30, 30, 30);
    rows.forEach((row, ri) => {
        if (ri % 2 === 0) {
            doc.setFillColor(245, 247, 252);
            doc.rect(x, y, totalW, cellHeight, 'F');
        }
        cx = x;
        row.forEach((cell, ci) => {
            doc.text(String(cell || ''), cx + padding, y + 5);
            cx += colWidths[ci];
        });
        y += cellHeight;
    });

    // Border
    doc.setDrawColor(200, 200, 210);
    doc.setLineWidth(0.2);
    doc.rect(x, y - (rows.length + 1) * cellHeight, totalW, (rows.length + 1) * cellHeight);

    return y + 5;
}

