function generateCambioIntermediario(doc, y, ml, cw, pw, mr) {
    const fecha = formatDate(getFieldValue('fecha'));
    const aseguradora = getFieldValue('aseguradora');
    const codigoGuiaBien = getFieldValue('codigo_guiabien');
    const ramo = getFieldValue('ramo');
    const nPoliza = getFieldValue('numero_poliza');
    const nombreTomador = getFieldValue('nombre_tomador');
    const tipoDoc = getFieldValue('tipo_doc');
    const numDoc = getFieldValue('numero_doc');

    // Date
    pdfSetNormal(doc);
    y = pdfWriteText(doc, `Medellín, ${fecha}`, ml, y, cw);
    y += 8;

    // Addressee
    pdfSetBold(doc);
    doc.text('Señores', ml, y); y += 5.5;
    doc.text(aseguradora.toUpperCase(), ml, y); y += 10;

    // Subject
    pdfSetSubject(doc);
    y = pdfWriteText(doc, 'Asunto: SOLICITUD CAMBIO DE INTERMEDIARIO.', ml, y, cw);
    y += 8;

    // Body
    pdfSetNormal(doc);
    y = pdfWriteText(doc, `Por medio de la presente, yo ${nombreTomador}, identificado con ${tipoDoc} No. ${numDoc}, en mi calidad de tomador de la póliza de ${ramo} No. ${nPoliza}, solicito realizar el cambio de intermediario de seguros.`, ml, y, cw);
    y += 6;
    y = pdfWriteText(doc, `El nuevo asesor debe ser GuíaBien Asesores en Seguros, código ${codigoGuiaBien}.`, ml, y, cw);
    y += 12;

    y = pdfWriteText(doc, 'Agradezco su gestión para que este cambio se vea reflejado a la mayor brevedad posible.', ml, y, cw);
    y += 15;

    // Signature
    pdfSetNormal(doc);
    doc.text('Atentamente,', ml, y); y += 8;
    y = pdfDrawSignatureLine(doc, y, ml, cw);
    pdfSetBold(doc);
    doc.text(nombreTomador, ml, y); y += 5.5;
    pdfSetNormal(doc);
    doc.text(`${tipoDoc} No. ${numDoc}`, ml, y);

    pdfFooter(doc, pw, doc.internal.pageSize.getHeight());
}

